module Mux(
  input [3:0] I,
  input [1:0] Sel,
  output reg Y
);
  always@(Sel or I)
  begin
    case(Sel)
      2'b00: Y = I[0];
      2'b01: Y = I[1];
      2'b10: Y = I[2];
      2'b11: Y = I[3];
    endcase
  end
endmodule

NET "Sel[0]" LOC = P22;
NET "Sel[1]" LOC = P21;
NET "I[0]"   LOC = P17;
NET "I[1]"   LOC = P16;
NET "I[2]"   LOC = P15;
NET "I[3]"   LOC = P14;
NET "Y"      LOC = P24;

module OR_using_mux(
  input A,
  input B,
  output Y
);
  assign Y = A ? 1 : B;
endmodule

NET "A" LOC = P22;
NET "B" LOC = P21;
NET "Y" LOC = P30;
